import json
import os
import requests

def main():
    base_url = os.getenv('BASE_URL')
    headers = {}
    auth = os.getenv('HEADER_AUTHORIZATION')
    if auth:
        headers['Authorization'] = auth

    response = requests.get(f'{base_url}/api-docs', headers=headers, timeout=10)

    result = {
        'request': {
            'method': 'GET',
            'url': f'{base_url}/api-docs',
            'headers': headers,
            'body': None
        },
        'response': {
            'status': response.status_code,
            'body': response.text[:200]
        }
    }
    print('__RESULT__=' + json.dumps(result, ensure_ascii=False))
    assert response.status_code == 200

if __name__ == '__main__':
    main()
